import redis
import json
import sys

class RedisLuaClient:
    def __init__(self, host='localhost', port=6379, db=0, password=None):
        self.client = redis.Redis(
            host=host,
            port=port,
            db=db,
            password=password,
            decode_responses=True
        )
    
    def execute_lua_script(self, script, keys=None, args=None):
        if keys is None:
            keys = []
        if args is None:
            args = []
        
        result = self.client.eval(script, len(keys), *keys, *args)
        return result
    
    def execute_lua_from_input(self):
        print("Enter Lua script (end with 'END' on a new line):")
        script_lines = []
        while True:
            line = input()
            if line.strip() == 'END':
                break
            script_lines.append(line)
        
        script = '\n'.join(script_lines)
        
        keys_input = input("Enter keys (comma-separated, or press Enter for none): ").strip()
        keys = [k.strip() for k in keys_input.split(',')] if keys_input else []
        
        args_input = input("Enter arguments (comma-separated, or press Enter for none): ").strip()
        args = [a.strip() for a in args_input.split(',')] if args_input else []
        
        result = self.execute_lua_script(script, keys, args)
        return result
    
    def batch_execute(self, operations):
        results = []
        for op in operations:
            script = op.get('script', '')
            keys = op.get('keys', [])
            args = op.get('args', [])
            result = self.execute_lua_script(script, keys, args)
            results.append(result)
        return results
    
    def register_script(self, script):
        return self.client.script_load(script)
    
    def execute_registered_script(self, sha, keys=None, args=None):
        if keys is None:
            keys = []
        if args is None:
            args = []
        
        result = self.client.evalsha(sha, len(keys), *keys, *args)
        return result


